script:
frappe.ui.form.on('Payment Terms Template', 'validate', (frm) => {
    if(!frm.doc.terms.template_name.startsWith('Rat')) return;

    frm.doc.terms.forEach((term) => {
        term.invoice_portion = 100 / frm.doc.terms.length;
    });
});

frappe.ui.form.on('Sales Order', {
	refresh(frm) {
	    frm.trigger("populate_manufacturing_html");	
	},
	async populate_manufacturing_html(frm) {
	    // Generate HTML
        const html = `<div>
            <p>Ciao Talat El Beick</p>
        </div>`;

	    frm.set_df_property("manufacturing_html", "options", html);
	},
});
